import type { ReactNode, Ref } from 'react';
import type { LabelProps as AriaLabelProps } from 'react-aria-components';
import { Label as AriaLabel } from 'react-aria-components';
import { Tooltip } from '@/components/atoms/Tooltip';
import { cx } from '@/utils/cx';

export interface LabelProps extends AriaLabelProps {
  children: ReactNode;
  isRequired?: boolean;
  tooltip?: string;
  tooltipDescription?: string;
  ref?: Ref<HTMLLabelElement>;
}

export const Label = ({
  isRequired,
  tooltip,
  tooltipDescription,
  className,
  ...props
}: LabelProps) => {
  return (
    <AriaLabel
      // Used for conditionally hiding/showing the label element via CSS:
      // <Input label="Visible only on mobile" className="lg:**:data-label:hidden" />
      data-label="true"
      {...props}
      className={cx(
        'flex cursor-default items-center gap-0.5 text-sm font-medium text-secondary',
        className,
      )}
    >
      {props.children}

      <span
        className={cx(
          'hidden text-brand-tertiary',
          isRequired && 'block',
          typeof isRequired === 'undefined' && 'group-required:block',
        )}
      >
        *
      </span>

      {tooltip && (
        <Tooltip
          title={tooltip}
          description={tooltipDescription}
          placement="top"
          isHelpIconTrigger
          // TooltipTrigger inherits the disabled state from the parent form
          // field, but we want the tooltip enabled even if the field is disabled.
          triggerProps={{ isDisabled: false }}
          data-id="label-tooltip"
        />
      )}
    </AriaLabel>
  );
};

Label.displayName = 'Label';
